-- Bulgarian Addresses Database
-- Generated from bulgarian_addresses_with_coords.csv

DROP TABLE IF EXISTS bulgarian_addresses;

CREATE TABLE bulgarian_addresses (
    id SERIAL PRIMARY KEY,
    region VARCHAR(100) NOT NULL,
    city VARCHAR(100) NOT NULL,
    street VARCHAR(255),
    neighborhood VARCHAR(100),
    settlement VARCHAR(100),
    type VARCHAR(20) NOT NULL,
    postal_code VARCHAR(10),
    lat DECIMAL(10, 7),
    lng DECIMAL(10, 7)
);

CREATE INDEX idx_region ON bulgarian_addresses(region);
CREATE INDEX idx_city ON bulgarian_addresses(city);
CREATE INDEX idx_type ON bulgarian_addresses(type);
CREATE INDEX idx_postal_code ON bulgarian_addresses(postal_code);

